        assert!(configuration.executables[&ModOrganizerTool::XEdit].contains(&PathBuf::from("C:/Tools/FO4Edit.exe")));
        assert!(configuration.executables[&ModOrganizerTool::BSArch].contains(&PathBuf::from("C:/Tools/BSArch.exe")));
    }

    #[test]
    fn mo2_instance_discovery_checks_adjacent_files_before_hkcu_current_instance() {
        let filesystem = FakeFilesystem::default()
            .with_file(
