    #[test]
    fn mo2_missing_selected_profile_returns_typed_manager_error() {
        let filesystem = FakeFilesystem::default().with_file(
            "C:/MO2/ModOrganizer.ini",
            "[General]\n\
             gameName=Fallout 4\n\
             gamePath=C:/Games/Fallout 4\n",
