                .parent()
                .map(normalize_lexically)
                .unwrap_or_else(|| PathBuf::from(".")))
        } else {
            Ok(normalized)
        }
    }

    fn is_fo4_dir(&self, path: &Path) -> Result<bool, PlatformError> {
